-- Warehouse transfers, stock adjustments, immutable operation controls, and journal support.

create or replace function private.prepare_business_journal_line()
returns trigger
language plpgsql
security definer
set search_path to pg_catalog, public, private
as $$
declare target_entry_id uuid; entry_business_id uuid; entry_status text; entry_source_type text; entry_source_id uuid; entry_exchange_rate numeric(24,10); rounding_scale smallint; account_valid boolean; account_system_key text; invoice_total_base numeric(24,6); invoice_tax_base numeric(24,6); invoice_revenue_base numeric(24,6); invoice_revenue_and_tax_base numeric(24,6); first_revenue_account_id uuid; sales_payment_base numeric(24,6); supplier_bill_total_base numeric(24,6); supplier_bill_tax_base numeric(24,6); supplier_bill_allocation_base numeric(24,6); supplier_payment_base numeric(24,6);
begin
 target_entry_id:=case when tg_op='DELETE' then old.journal_entry_id else new.journal_entry_id end;
 select entry.business_id,entry.status,entry.source_type,entry.source_id,entry.exchange_rate into entry_business_id,entry_status,entry_source_type,entry_source_id,entry_exchange_rate from public.business_journal_entries entry where entry.id=target_entry_id for update;
 if not found then raise exception 'Journal entry does not exist.' using errcode='23503'; end if;
 if entry_status<>'draft' then raise exception 'Posted journal lines are immutable.' using errcode='55000'; end if;
 if tg_op='DELETE' then return old; end if;
 if new.business_id<>entry_business_id then raise exception 'Journal line tenant does not match its entry.' using errcode='23514'; end if;
 select account.system_key,account.is_active and (
  (entry_source_type='manual' and account.allow_manual_posting)
  or (entry_source_type='sales_invoice' and account.system_key in('accounts_receivable','sales_revenue','service_revenue','taxes_payable'))
  or (entry_source_type='sales_payment' and account.system_key in('cash','bank','accounts_receivable'))
  or (entry_source_type='purchase_bill' and (account.system_key in('accounts_payable','tax_recoverable') or account.account_type='expense' or (account.account_type='asset' and account.system_key in('inventory','prepaid_expenses','fixed_assets'))))
  or (entry_source_type='supplier_payment' and account.system_key in('cash','bank','accounts_payable'))
  or (entry_source_type='inventory_cogs' and exists(select 1 from public.business_stock_movements movement join public.business_products product on product.business_id=movement.business_id and product.id=movement.product_id where movement.business_id=new.business_id and movement.source_type='sales_invoice' and movement.source_id=entry_source_id and movement.status='draft' and new.account_id in(product.inventory_account_id,product.cogs_account_id)))
  or (entry_source_type='stock_adjustment' and (account.system_key in('inventory_adjustment_gain','inventory_adjustment_loss') or exists(select 1 from public.business_stock_adjustment_lines adjustment_line join public.business_products product on product.business_id=adjustment_line.business_id and product.id=adjustment_line.product_id where adjustment_line.business_id=new.business_id and adjustment_line.adjustment_id=entry_source_id and product.inventory_account_id=new.account_id)))
  or (entry_source_type='sales_return' and (account.system_key in('accounts_receivable','customer_credits','taxes_payable') or exists(select 1 from public.business_sales_return_lines return_line join public.business_sales_invoice_lines invoice_line on invoice_line.business_id=return_line.business_id and invoice_line.id=return_line.invoice_line_id left join public.business_products product on product.business_id=return_line.business_id and product.id=return_line.product_id where return_line.business_id=new.business_id and return_line.return_id=entry_source_id and new.account_id in(invoice_line.revenue_account_id,product.inventory_account_id,product.cogs_account_id))))
  or (entry_source_type='purchase_return' and (account.system_key in('accounts_payable','supplier_refunds_receivable','tax_recoverable','inventory_adjustment_gain','inventory_adjustment_loss') or exists(select 1 from public.business_purchase_return_lines return_line join public.business_supplier_bill_lines bill_line on bill_line.business_id=return_line.business_id and bill_line.id=return_line.bill_line_id left join public.business_products product on product.business_id=return_line.business_id and product.id=return_line.product_id where return_line.business_id=new.business_id and return_line.return_id=entry_source_id and new.account_id in(bill_line.allocation_account_id,product.inventory_account_id))))
 ) into account_system_key,account_valid from public.business_chart_of_accounts account where account.id=new.account_id and account.business_id=new.business_id;
 if not coalesce(account_valid,false) then raise exception 'Account is inactive, restricted, or invalid for this journal source.' using errcode='23514'; end if;
 select settings.rounding_scale into rounding_scale from public.business_accounting_settings settings where settings.business_id=new.business_id;
 if rounding_scale is null then raise exception 'Accounting settings are missing.' using errcode='23503'; end if;
 if entry_source_type in('manual','inventory_cogs','stock_adjustment','sales_return','purchase_return') then new.debit_base:=round(new.debit_transaction*entry_exchange_rate,rounding_scale);new.credit_base:=round(new.credit_transaction*entry_exchange_rate,rounding_scale);return new;end if;
 if entry_source_type='sales_invoice' then
  select invoice.total_base,invoice.tax_base into invoice_total_base,invoice_tax_base from public.business_sales_invoices invoice where invoice.id=entry_source_id and invoice.business_id=new.business_id and invoice.status='draft';
  if invoice_total_base is null then raise exception 'Sales invoice accounting source is unavailable.' using errcode='P0002'; end if;
  if account_system_key='accounts_receivable' then new.debit_base:=invoice_total_base;new.credit_base:=0;return new;end if;
  if account_system_key='taxes_payable' then new.debit_base:=0;new.credit_base:=invoice_tax_base;return new;end if;
  select coalesce(sum(line.net_base) filter(where line.revenue_account_id=new.account_id),0),coalesce(sum(line.net_base),0)+invoice_tax_base,min(line.revenue_account_id::text)::uuid into invoice_revenue_base,invoice_revenue_and_tax_base,first_revenue_account_id from public.business_sales_invoice_lines line where line.business_id=new.business_id and line.invoice_id=entry_source_id;
  if new.account_id=first_revenue_account_id then invoice_revenue_base:=invoice_revenue_base+(invoice_total_base-invoice_revenue_and_tax_base);end if;
  new.debit_base:=0;new.credit_base:=invoice_revenue_base;return new;
 end if;
 if entry_source_type='sales_payment' then select payment.amount_base into sales_payment_base from public.business_sales_payments payment where payment.id=entry_source_id and payment.business_id=new.business_id and payment.status='draft';if sales_payment_base is null then raise exception 'Sales payment accounting source is unavailable.' using errcode='P0002';end if;if account_system_key in('cash','bank') then new.debit_base:=sales_payment_base;new.credit_base:=0;else new.debit_base:=0;new.credit_base:=sales_payment_base;end if;return new;end if;
 if entry_source_type='purchase_bill' then select bill.total_base,bill.tax_base into supplier_bill_total_base,supplier_bill_tax_base from public.business_supplier_bills bill where bill.id=entry_source_id and bill.business_id=new.business_id and bill.status='draft';if supplier_bill_total_base is null then raise exception 'Supplier bill accounting source is unavailable.' using errcode='P0002';end if;if account_system_key='accounts_payable' then new.debit_base:=0;new.credit_base:=supplier_bill_total_base;return new;end if;if account_system_key='tax_recoverable' then new.debit_base:=supplier_bill_tax_base;new.credit_base:=0;return new;end if;select coalesce(sum(line.net_base),0) into supplier_bill_allocation_base from public.business_supplier_bill_lines line where line.business_id=new.business_id and line.bill_id=entry_source_id and line.allocation_account_id=new.account_id;new.debit_base:=supplier_bill_allocation_base;new.credit_base:=0;return new;end if;
 if entry_source_type='supplier_payment' then select payment.amount_base into supplier_payment_base from public.business_supplier_payments payment where payment.id=entry_source_id and payment.business_id=new.business_id and payment.status='draft';if supplier_payment_base is null then raise exception 'Supplier payment accounting source is unavailable.' using errcode='P0002';end if;if account_system_key='accounts_payable' then new.debit_base:=supplier_payment_base;new.credit_base:=0;else new.debit_base:=0;new.credit_base:=supplier_payment_base;end if;return new;end if;
 raise exception 'Unsupported journal source.' using errcode='22023';
end; $$;

create or replace function private.enforce_inventory_operation_header_state() returns trigger language plpgsql security definer set search_path to pg_catalog,public,private as $$ begin if tg_op='DELETE' then if old.status<>'draft' then raise exception 'Posted inventory operations are immutable.' using errcode='55000';end if;return old;end if;if old.status<>'draft' then raise exception 'Posted inventory operations are immutable.' using errcode='55000';end if;if new.business_id<>old.business_id or new.created_by<>old.created_by then raise exception 'Inventory operation ownership cannot be reassigned.' using errcode='23514';end if;return new;end; $$;
create or replace function private.enforce_inventory_operation_line_state() returns trigger language plpgsql security definer set search_path to pg_catalog,public,private as $$ declare parent_table text:=tg_argv[0];parent_column text:=tg_argv[1];target_business_id uuid;target_parent_id uuid;parent_status text;begin target_business_id:=case when tg_op='DELETE' then old.business_id else new.business_id end;target_parent_id:=(case when tg_op='DELETE' then to_jsonb(old)->>parent_column else to_jsonb(new)->>parent_column end)::uuid;execute format('select status from public.%I where business_id=$1 and id=$2 for update',parent_table) into parent_status using target_business_id,target_parent_id;if parent_status is null then raise exception 'Inventory operation header does not exist.' using errcode='23503';end if;if parent_status<>'draft' then raise exception 'Posted inventory operation lines are immutable.' using errcode='55000';end if;if tg_op='DELETE' then return old;end if;return new;end; $$;
do $$ declare header_table text;begin foreach header_table in array array['business_warehouse_transfers','business_stock_adjustments','business_sales_returns','business_purchase_returns'] loop execute format('drop trigger if exists %I_enforce_state on public.%I',header_table,header_table);execute format('create trigger %I_enforce_state before update or delete on public.%I for each row execute function private.enforce_inventory_operation_header_state()',header_table,header_table);execute format('drop trigger if exists %I_set_updated_at on public.%I',header_table,header_table);execute format('create trigger %I_set_updated_at before update on public.%I for each row execute function private.set_business_workspace_updated_at()',header_table,header_table);end loop;end; $$;
drop trigger if exists business_warehouse_transfer_lines_enforce_state on public.business_warehouse_transfer_lines;create trigger business_warehouse_transfer_lines_enforce_state before insert or update or delete on public.business_warehouse_transfer_lines for each row execute function private.enforce_inventory_operation_line_state('business_warehouse_transfers','transfer_id');
drop trigger if exists business_stock_adjustment_lines_enforce_state on public.business_stock_adjustment_lines;create trigger business_stock_adjustment_lines_enforce_state before insert or update or delete on public.business_stock_adjustment_lines for each row execute function private.enforce_inventory_operation_line_state('business_stock_adjustments','adjustment_id');
drop trigger if exists business_sales_return_lines_enforce_state on public.business_sales_return_lines;create trigger business_sales_return_lines_enforce_state before insert or update or delete on public.business_sales_return_lines for each row execute function private.enforce_inventory_operation_line_state('business_sales_returns','return_id');
drop trigger if exists business_purchase_return_lines_enforce_state on public.business_purchase_return_lines;create trigger business_purchase_return_lines_enforce_state before insert or update or delete on public.business_purchase_return_lines for each row execute function private.enforce_inventory_operation_line_state('business_purchase_returns','return_id');

create or replace function private.next_business_inventory_operation_number(p_business_id uuid,p_operation text) returns bigint language plpgsql security definer set search_path to pg_catalog,public,private as $$ declare assigned_number bigint;begin if p_operation='transfer' then update public.business_inventory_settings settings set next_transfer_number=settings.next_transfer_number+1,updated_at=now() where settings.business_id=p_business_id returning settings.next_transfer_number-1 into assigned_number;elsif p_operation='adjustment' then update public.business_inventory_settings settings set next_adjustment_number=settings.next_adjustment_number+1,updated_at=now() where settings.business_id=p_business_id returning settings.next_adjustment_number-1 into assigned_number;elsif p_operation='sales_return' then update public.business_inventory_settings settings set next_sales_return_number=settings.next_sales_return_number+1,updated_at=now() where settings.business_id=p_business_id returning settings.next_sales_return_number-1 into assigned_number;elsif p_operation='purchase_return' then update public.business_inventory_settings settings set next_purchase_return_number=settings.next_purchase_return_number+1,updated_at=now() where settings.business_id=p_business_id returning settings.next_purchase_return_number-1 into assigned_number;else raise exception 'Unsupported inventory operation sequence.' using errcode='22023';end if;if assigned_number is null then raise exception 'Inventory operation settings are missing.' using errcode='23503';end if;return assigned_number;end; $$;

create or replace function private.post_business_inventory_operation_journal(p_business_id uuid,p_entry_date date,p_source_type text,p_source_id uuid,p_reference text,p_description text,p_lines jsonb,p_user_id uuid) returns uuid language plpgsql security definer set search_path to pg_catalog,public,private as $$ declare base_currency text;selected_period_id uuid;created_entry_id uuid;line_item jsonb;line_number smallint:=0;account_uuid uuid;debit_amount numeric(24,6);credit_amount numeric(24,6);begin if p_source_type not in('stock_adjustment','sales_return','purchase_return') then raise exception 'Unsupported inventory operation journal source.' using errcode='22023';end if;if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)<2 or jsonb_array_length(p_lines)>200 then raise exception 'Inventory journals require 2 to 200 lines.' using errcode='22023';end if;select business.base_currency into base_currency from public.businesses business where business.id=p_business_id and business.status='active';if base_currency is null then raise exception 'Active business not found.' using errcode='P0002';end if;select period.id into selected_period_id from public.business_fiscal_periods period where period.business_id=p_business_id and period.status='open' and p_entry_date between period.starts_on and period.ends_on order by period.starts_on desc limit 1;if selected_period_id is null then raise exception 'No open fiscal period contains the inventory operation date.' using errcode='22008';end if;insert into public.business_journal_entries(business_id,entry_date,fiscal_period_id,source_type,source_id,reference,description,status,transaction_currency,exchange_rate,created_by) values(p_business_id,p_entry_date,selected_period_id,p_source_type,p_source_id,nullif(btrim(coalesce(p_reference,'')),''),btrim(p_description),'draft',base_currency,1,p_user_id) returning id into created_entry_id;for line_item in select value from jsonb_array_elements(p_lines) loop line_number:=line_number+1;begin account_uuid:=(line_item->>'account_id')::uuid;debit_amount:=coalesce(nullif(line_item->>'debit','')::numeric,0);credit_amount:=coalesce(nullif(line_item->>'credit','')::numeric,0);exception when invalid_text_representation then raise exception 'Inventory journal lines contain invalid account or amount values.' using errcode='22023';end;insert into public.business_journal_lines(business_id,journal_entry_id,line_number,account_id,description,debit_transaction,credit_transaction) values(p_business_id,created_entry_id,line_number,account_uuid,nullif(btrim(coalesce(line_item->>'description','')),''),debit_amount,credit_amount);end loop;update public.business_journal_entries entry set status='posted' where entry.id=created_entry_id and entry.business_id=p_business_id;return created_entry_id;end; $$;

create or replace function private.create_business_warehouse_transfer_internal(p_business_id uuid,p_transfer_date date,p_from_warehouse_id uuid,p_to_warehouse_id uuid,p_lines jsonb,p_notes text,p_idempotency_key text) returns uuid language plpgsql security definer set search_path to pg_catalog,public,private as $$ declare current_user_id uuid:=auth.uid();existing_id uuid;transfer_id uuid;assigned_number bigint;transfer_code text;line_item jsonb;line_number smallint:=0;product_uuid uuid;quantity_requested numeric(24,6);seen_products uuid[]:='{}'::uuid[];source_quantity numeric(24,6);source_value numeric(24,6);source_average numeric(24,6);destination_quantity numeric(24,6);destination_value numeric(24,6);transfer_value numeric(24,6);destination_new_quantity numeric(24,6);destination_new_value numeric(24,6);destination_new_average numeric(24,6);transfer_line_id uuid;out_movement_id uuid;in_movement_id uuid;begin if current_user_id is null then raise exception 'Authentication required.' using errcode='42501';end if;if not exists(select 1 from public.business_members membership where membership.business_id=p_business_id and membership.user_id=current_user_id and membership.status='active' and (membership.role in('owner','admin','manager','inventory') or '*'=any(membership.permissions) or 'inventory.manage'=any(membership.permissions) or 'inventory.transfer'=any(membership.permissions))) then raise exception 'Inventory transfer permission required.' using errcode='42501';end if;if p_transfer_date is null then raise exception 'Transfer date is required.' using errcode='22004';end if;if p_from_warehouse_id=p_to_warehouse_id then raise exception 'Source and destination warehouses must be different.' using errcode='22023';end if;if p_idempotency_key is not null then select transfer.id into existing_id from public.business_warehouse_transfers transfer where transfer.business_id=p_business_id and transfer.idempotency_key=nullif(btrim(p_idempotency_key),'');if existing_id is not null then return existing_id;end if;end if;if not exists(select 1 from public.business_warehouses warehouse where warehouse.business_id=p_business_id and warehouse.id=p_from_warehouse_id and warehouse.status='active') or not exists(select 1 from public.business_warehouses warehouse where warehouse.business_id=p_business_id and warehouse.id=p_to_warehouse_id and warehouse.status='active') then raise exception 'Active source and destination warehouses are required.' using errcode='P0002';end if;if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)<1 or jsonb_array_length(p_lines)>100 then raise exception 'Warehouse transfers require 1 to 100 product lines.' using errcode='22023';end if;assigned_number:=private.next_business_inventory_operation_number(p_business_id,'transfer');transfer_code:='TRF-'||lpad(assigned_number::text,6,'0');insert into public.business_warehouse_transfers(business_id,transfer_number,transfer_code,transfer_date,from_warehouse_id,to_warehouse_id,status,notes,idempotency_key,created_by) values(p_business_id,assigned_number,transfer_code,p_transfer_date,p_from_warehouse_id,p_to_warehouse_id,'draft',nullif(btrim(coalesce(p_notes,'')),''),nullif(btrim(coalesce(p_idempotency_key,'')),''),current_user_id) returning id into transfer_id;for line_item in select value from jsonb_array_elements(p_lines) loop line_number:=line_number+1;begin product_uuid:=(line_item->>'product_id')::uuid;quantity_requested:=coalesce(nullif(line_item->>'quantity','')::numeric,0);exception when invalid_text_representation then raise exception 'Transfer lines contain invalid product or quantity values.' using errcode='22023';end;if quantity_requested<=0 then raise exception 'Transfer quantity must be greater than zero.' using errcode='22023';end if;if product_uuid=any(seen_products) then raise exception 'A product can appear only once per warehouse transfer.' using errcode='23505';end if;seen_products:=array_append(seen_products,product_uuid);if not exists(select 1 from public.business_products product where product.business_id=p_business_id and product.id=product_uuid and product.status='active') then raise exception 'Active inventory product not found.' using errcode='P0002';end if;insert into public.business_inventory_balances(business_id,product_id,warehouse_id) values(p_business_id,product_uuid,p_from_warehouse_id),(p_business_id,product_uuid,p_to_warehouse_id) on conflict(business_id,product_id,warehouse_id) do nothing;perform 1 from public.business_inventory_balances balance where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id in(p_from_warehouse_id,p_to_warehouse_id) order by balance.warehouse_id for update;select balance.quantity_on_hand,balance.inventory_value_base,balance.average_cost_base into source_quantity,source_value,source_average from public.business_inventory_balances balance where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_from_warehouse_id;select balance.quantity_on_hand,balance.inventory_value_base into destination_quantity,destination_value from public.business_inventory_balances balance where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_to_warehouse_id;if quantity_requested>source_quantity then raise exception 'Insufficient stock for warehouse transfer.' using errcode='22023';end if;transfer_value:=case when quantity_requested=source_quantity then source_value else round(source_average*quantity_requested,6) end;update public.business_inventory_balances balance set quantity_on_hand=source_quantity-quantity_requested,inventory_value_base=case when source_quantity-quantity_requested=0 then 0 else greatest(source_value-transfer_value,0) end,average_cost_base=case when source_quantity-quantity_requested=0 then 0 else source_average end,updated_at=now() where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_from_warehouse_id;destination_new_quantity:=destination_quantity+quantity_requested;destination_new_value:=destination_value+transfer_value;destination_new_average:=case when destination_new_quantity=0 then 0 else round(destination_new_value/destination_new_quantity,6) end;update public.business_inventory_balances balance set quantity_on_hand=destination_new_quantity,inventory_value_base=destination_new_value,average_cost_base=destination_new_average,updated_at=now() where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_to_warehouse_id;insert into public.business_warehouse_transfer_lines(business_id,transfer_id,line_number,product_id,quantity,unit_cost_base,total_value_base) values(p_business_id,transfer_id,line_number,product_uuid,quantity_requested,source_average,transfer_value) returning id into transfer_line_id;insert into public.business_stock_movements(business_id,movement_number,movement_type,movement_date,product_id,warehouse_id,quantity,unit_cost_base,total_value_base,source_type,source_id,source_line_id,status,notes,created_by,posted_at) values(p_business_id,private.next_business_inventory_movement_number(p_business_id),'transfer_out',p_transfer_date,product_uuid,p_from_warehouse_id,quantity_requested,source_average,transfer_value,'warehouse_transfer',transfer_id,transfer_line_id,'posted','Warehouse transfer out',current_user_id,now()) returning id into out_movement_id;insert into public.business_stock_movements(business_id,movement_number,movement_type,movement_date,product_id,warehouse_id,quantity,unit_cost_base,total_value_base,source_type,source_id,source_line_id,status,notes,created_by,posted_at) values(p_business_id,private.next_business_inventory_movement_number(p_business_id),'transfer_in',p_transfer_date,product_uuid,p_to_warehouse_id,quantity_requested,source_average,transfer_value,'warehouse_transfer',transfer_id,transfer_line_id,'posted','Warehouse transfer in',current_user_id,now()) returning id into in_movement_id;update public.business_warehouse_transfer_lines transfer_line set out_movement_id=out_movement_id,in_movement_id=in_movement_id where transfer_line.business_id=p_business_id and transfer_line.id=transfer_line_id;end loop;update public.business_warehouse_transfers transfer set status='posted',posted_at=now(),updated_at=now() where transfer.business_id=p_business_id and transfer.id=transfer_id;return transfer_id;end; $$;
create or replace function public.create_business_warehouse_transfer(p_business_id uuid,p_transfer_date date,p_from_warehouse_id uuid,p_to_warehouse_id uuid,p_lines jsonb default '[]'::jsonb,p_notes text default null,p_idempotency_key text default null) returns uuid language plpgsql set search_path to pg_catalog,public,private as $$ begin return private.create_business_warehouse_transfer_internal(p_business_id,p_transfer_date,p_from_warehouse_id,p_to_warehouse_id,p_lines,p_notes,p_idempotency_key);end; $$;

create or replace function private.create_business_stock_adjustment_internal(p_business_id uuid,p_adjustment_date date,p_warehouse_id uuid,p_reason text,p_lines jsonb,p_notes text,p_idempotency_key text) returns uuid language plpgsql security definer set search_path to pg_catalog,public,private as $$ declare current_user_id uuid:=auth.uid();existing_id uuid;adjustment_id uuid;assigned_number bigint;adjustment_code text;line_item jsonb;line_number smallint:=0;product_uuid uuid;counted_quantity numeric(24,6);supplied_unit_cost numeric(24,6);product_cost_hint numeric(24,6);seen_products uuid[]:='{}'::uuid[];system_quantity numeric(24,6);system_value numeric(24,6);system_average numeric(24,6);quantity_delta numeric(24,6);unit_cost numeric(24,6);value_change numeric(24,6);new_quantity numeric(24,6);new_value numeric(24,6);new_average numeric(24,6);adjustment_line_id uuid;movement_id uuid;journal_id uuid;journal_lines jsonb;gain_account_id uuid;loss_account_id uuid;begin if current_user_id is null then raise exception 'Authentication required.' using errcode='42501';end if;if not exists(select 1 from public.business_members membership where membership.business_id=p_business_id and membership.user_id=current_user_id and membership.status='active' and (membership.role in('owner','admin','manager','inventory') or '*'=any(membership.permissions) or 'inventory.manage'=any(membership.permissions) or 'inventory.adjust'=any(membership.permissions))) then raise exception 'Inventory adjustment permission required.' using errcode='42501';end if;if p_adjustment_date is null then raise exception 'Adjustment date is required.' using errcode='22004';end if;if char_length(btrim(coalesce(p_reason,'')))<2 then raise exception 'Adjustment reason is required.' using errcode='22023';end if;if p_idempotency_key is not null then select adjustment.id into existing_id from public.business_stock_adjustments adjustment where adjustment.business_id=p_business_id and adjustment.idempotency_key=nullif(btrim(p_idempotency_key),'');if existing_id is not null then return existing_id;end if;end if;if not exists(select 1 from public.business_warehouses warehouse where warehouse.business_id=p_business_id and warehouse.id=p_warehouse_id and warehouse.status='active') then raise exception 'Active adjustment warehouse not found.' using errcode='P0002';end if;if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)<1 or jsonb_array_length(p_lines)>100 then raise exception 'Stock adjustments require 1 to 100 counted product lines.' using errcode='22023';end if;select account.id into gain_account_id from public.business_chart_of_accounts account where account.business_id=p_business_id and account.system_key='inventory_adjustment_gain' and account.is_active;select account.id into loss_account_id from public.business_chart_of_accounts account where account.business_id=p_business_id and account.system_key='inventory_adjustment_loss' and account.is_active;if gain_account_id is null or loss_account_id is null then raise exception 'Inventory adjustment accounts are missing.' using errcode='23503';end if;assigned_number:=private.next_business_inventory_operation_number(p_business_id,'adjustment');adjustment_code:='ADJ-'||lpad(assigned_number::text,6,'0');insert into public.business_stock_adjustments(business_id,adjustment_number,adjustment_code,adjustment_date,warehouse_id,reason,status,notes,idempotency_key,created_by) values(p_business_id,assigned_number,adjustment_code,p_adjustment_date,p_warehouse_id,btrim(p_reason),'draft',nullif(btrim(coalesce(p_notes,'')),''),nullif(btrim(coalesce(p_idempotency_key,'')),''),current_user_id) returning id into adjustment_id;for line_item in select value from jsonb_array_elements(p_lines) loop line_number:=line_number+1;begin product_uuid:=(line_item->>'product_id')::uuid;counted_quantity:=coalesce(nullif(line_item->>'counted_quantity','')::numeric,-1);supplied_unit_cost:=coalesce(nullif(line_item->>'unit_cost_base','')::numeric,0);exception when invalid_text_representation then raise exception 'Adjustment lines contain invalid product, quantity, or cost values.' using errcode='22023';end;if counted_quantity<0 or supplied_unit_cost<0 then raise exception 'Counted quantity and unit cost cannot be negative.' using errcode='22023';end if;if product_uuid=any(seen_products) then raise exception 'A product can appear only once per stock adjustment.' using errcode='23505';end if;seen_products:=array_append(seen_products,product_uuid);select product.purchase_cost_hint into product_cost_hint from public.business_products product where product.business_id=p_business_id and product.id=product_uuid and product.status='active';if not found then raise exception 'Active inventory product not found.' using errcode='P0002';end if;insert into public.business_inventory_balances(business_id,product_id,warehouse_id) values(p_business_id,product_uuid,p_warehouse_id) on conflict(business_id,product_id,warehouse_id) do nothing;select balance.quantity_on_hand,balance.inventory_value_base,balance.average_cost_base into system_quantity,system_value,system_average from public.business_inventory_balances balance where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_warehouse_id for update;quantity_delta:=counted_quantity-system_quantity;if quantity_delta=0 then raise exception 'Counted quantity must differ from system quantity.' using errcode='22023';end if;if quantity_delta>0 then unit_cost:=case when system_quantity>0 then system_average when supplied_unit_cost>0 then supplied_unit_cost else product_cost_hint end;if unit_cost<=0 then raise exception 'A positive opening adjustment requires a unit cost.' using errcode='22023';end if;value_change:=round(unit_cost*quantity_delta,6);new_quantity:=counted_quantity;new_value:=system_value+value_change;new_average:=round(new_value/new_quantity,6);else unit_cost:=system_average;value_change:=case when counted_quantity=0 then system_value else round(system_average*abs(quantity_delta),6) end;new_quantity:=counted_quantity;new_value:=case when counted_quantity=0 then 0 else greatest(system_value-value_change,0) end;new_average:=case when counted_quantity=0 then 0 else system_average end;end if;update public.business_inventory_balances balance set quantity_on_hand=new_quantity,inventory_value_base=new_value,average_cost_base=new_average,updated_at=now() where balance.business_id=p_business_id and balance.product_id=product_uuid and balance.warehouse_id=p_warehouse_id;insert into public.business_stock_adjustment_lines(business_id,adjustment_id,line_number,product_id,system_quantity,counted_quantity,quantity_delta,unit_cost_base,value_change_base) values(p_business_id,adjustment_id,line_number,product_uuid,system_quantity,counted_quantity,quantity_delta,unit_cost,value_change) returning id into adjustment_line_id;insert into public.business_stock_movements(business_id,movement_number,movement_type,movement_date,product_id,warehouse_id,quantity,unit_cost_base,total_value_base,source_type,source_id,source_line_id,status,notes,created_by) values(p_business_id,private.next_business_inventory_movement_number(p_business_id),case when quantity_delta>0 then 'adjustment_in' else 'adjustment_out' end,p_adjustment_date,product_uuid,p_warehouse_id,abs(quantity_delta),unit_cost,value_change,'stock_adjustment',adjustment_id,adjustment_line_id,'draft',btrim(p_reason),current_user_id) returning id into movement_id;update public.business_stock_adjustment_lines adjustment_line set movement_id=movement_id where adjustment_line.business_id=p_business_id and adjustment_line.id=adjustment_line_id;end loop;select coalesce(jsonb_agg(line_json order by sort_order,account_id),'[]'::jsonb) into journal_lines from (select 1 sort_order,product.inventory_account_id account_id,jsonb_build_object('account_id',product.inventory_account_id,'debit',sum(adjustment_line.value_change_base),'credit',0,'description','Inventory count increase') line_json from public.business_stock_adjustment_lines adjustment_line join public.business_products product on product.business_id=adjustment_line.business_id and product.id=adjustment_line.product_id where adjustment_line.business_id=p_business_id and adjustment_line.adjustment_id=adjustment_id and adjustment_line.quantity_delta>0 group by product.inventory_account_id union all select 2,gain_account_id,jsonb_build_object('account_id',gain_account_id,'debit',0,'credit',sum(adjustment_line.value_change_base),'description','Inventory adjustment gain') from public.business_stock_adjustment_lines adjustment_line where adjustment_line.business_id=p_business_id and adjustment_line.adjustment_id=adjustment_id and adjustment_line.quantity_delta>0 having sum(adjustment_line.value_change_base)>0 union all select 3,loss_account_id,jsonb_build_object('account_id',loss_account_id,'debit',sum(adjustment_line.value_change_base),'credit',0,'description','Inventory adjustment loss') from public.business_stock_adjustment_lines adjustment_line where adjustment_line.business_id=p_business_id and adjustment_line.adjustment_id=adjustment_id and adjustment_line.quantity_delta<0 having sum(adjustment_line.value_change_base)>0 union all select 4,product.inventory_account_id,jsonb_build_object('account_id',product.inventory_account_id,'debit',0,'credit',sum(adjustment_line.value_change_base),'description','Inventory count decrease') from public.business_stock_adjustment_lines adjustment_line join public.business_products product on product.business_id=adjustment_line.business_id and product.id=adjustment_line.product_id where adjustment_line.business_id=p_business_id and adjustment_line.adjustment_id=adjustment_id and adjustment_line.quantity_delta<0 group by product.inventory_account_id) journal_source;journal_id:=private.post_business_inventory_operation_journal(p_business_id,p_adjustment_date,'stock_adjustment',adjustment_id,adjustment_code,'Stock adjustment '||adjustment_code,journal_lines,current_user_id);update public.business_stock_movements movement set journal_entry_id=journal_id,status='posted',posted_at=now() where movement.business_id=p_business_id and movement.source_type='stock_adjustment' and movement.source_id=adjustment_id and movement.status='draft';update public.business_stock_adjustments adjustment set status='posted',journal_entry_id=journal_id,posted_at=now(),updated_at=now() where adjustment.business_id=p_business_id and adjustment.id=adjustment_id;return adjustment_id;end; $$;
create or replace function public.create_business_stock_adjustment(p_business_id uuid,p_adjustment_date date,p_warehouse_id uuid,p_reason text,p_lines jsonb default '[]'::jsonb,p_notes text default null,p_idempotency_key text default null) returns uuid language plpgsql set search_path to pg_catalog,public,private as $$ begin return private.create_business_stock_adjustment_internal(p_business_id,p_adjustment_date,p_warehouse_id,p_reason,p_lines,p_notes,p_idempotency_key);end; $$;
revoke all on function public.create_business_warehouse_transfer(uuid,date,uuid,uuid,jsonb,text,text) from public,anon;grant execute on function public.create_business_warehouse_transfer(uuid,date,uuid,uuid,jsonb,text,text) to authenticated,service_role;
revoke all on function public.create_business_stock_adjustment(uuid,date,uuid,text,jsonb,text,text) from public,anon;grant execute on function public.create_business_stock_adjustment(uuid,date,uuid,text,jsonb,text,text) to authenticated,service_role;
revoke execute on function private.enforce_inventory_operation_header_state() from public,anon,authenticated;revoke execute on function private.enforce_inventory_operation_line_state() from public,anon,authenticated;revoke execute on function private.next_business_inventory_operation_number(uuid,text) from public,anon,authenticated;revoke execute on function private.post_business_inventory_operation_journal(uuid,date,text,uuid,text,text,jsonb,uuid) from public,anon,authenticated;revoke execute on function private.create_business_warehouse_transfer_internal(uuid,date,uuid,uuid,jsonb,text,text) from public,anon,authenticated;revoke execute on function private.create_business_stock_adjustment_internal(uuid,date,uuid,text,jsonb,text,text) from public,anon,authenticated;
